      "keystrokes": "cat > /app/app.py << 'EOF'
from flask import Flask, request, jsonify
from transformers import pipeline
import os

app = Flask(__name__)

model_path = '/app/model_cache/sentiment_model'
classifier = None

try:
    classifier = pipeline('sentiment-analysis', model=model_path, tokenizer=model_path)
except Exception as e:
    print(f"Error loading model: {e}")
    classifier = None

@app.route('/sentiment', methods=['POST'])
def sentiment():
    if classifier is None:
        return jsonify({'error': 'Model not loaded'}), 500
    data = request.get_json()
    if not data or 'text' not in data:
        return jsonify({'error': 'Missing "text" field in JSON'}), 400
    text = data['text']
    if not isinstance(text, str) or not text.strip():
        return jsonify({'error': 'Text must be a non-empty string'}), 400
    try:
        result = classifier(text)[0]
        label = result['label']
        score = result['score']
        # label is either 'POSITIVE' or 'NEGATIVE' for this model
        sentiment = 'positive' if label == 'POSITIVE' else 'negative'
        confidence = {
            'positive': score if sentiment == 'positive' else 1 - score,
            'negative': score if sentiment == 'negative' else 1 - score
        }
        return jsonify({
            'sentiment': sentiment,
            'confidence': confidence
        })
    except Exception as e:
        return jsonify({'error': f'Inference error: {str(e)}'}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)
